import os
import tkinter as tk
from tkinter import ttk
from PIL import Image, ImageTk

# ========== CORES OFICIAIS ==========
BG_MAIN    = "#2b2b2b"
BG_PANEL   = "#3c3c3c"
BG_CARD    = "#444444"
BG_TOPBAR  = "#1e1e1e"
BG_SIDEBAR = "#252525"
BG_INPUT   = "#3a3a3a"

ACCENT     = "#4a90d9"
ACCENT_HOV = "#5ba3f0"
ACCENT_DRK = "#357abd"

TEXT_PRI   = "#e8e8e8"
TEXT_SEC   = "#a0a0a0"
TEXT_MUT   = "#6e6e6e"

SUCCESS    = "#5cb85c"
DANGER     = "#d9534f"
WARNING    = "#f0ad4e"
INFO       = "#5bc0de"

GREEN      = "#00ff7f"
RED        = "#ff4444"
YELLOW     = "#FFD700"

BORDER     = "#555555"
DIVIDER    = "#404040"

BTN_TEAL_BG  = "#2a4a4a"
BTN_TEAL_FG  = "#7ecaca"
BTN_TEAL_HOV = "#335555"
BTN_TEAL_AFG = "#9adada"

BTN_OLIVE_BG  = "#3a3a1e"
BTN_OLIVE_FG  = "#b8b06a"
BTN_OLIVE_HOV = "#484828"
BTN_OLIVE_AFG = "#d4cc88"

LOG_BG     = "#0d1117"
LOG_SENT   = "#d29922"
LOG_RECV   = "#3fb950"

# <<<LOGO_BASE64_START>>>
_LOGO_B64 = ""
_ICON_B64 = ""
# <<<LOGO_BASE64_END>>>

def _get_base_dir():
    """Retorna a pasta base — funciona tanto em source como em PyInstaller .exe"""
    import sys
    if getattr(sys, "frozen", False) and hasattr(sys, "_MEIPASS"):
        return sys._MEIPASS
    return os.path.dirname(os.path.abspath(__file__))

def load_logo(height=36):
    """Carrega o logo da topbar a partir do base64 embutido."""
    import base64 as _b64, io as _io
    try:
        raw   = _b64.b64decode(_LOGO_B64)
        img   = Image.open(_io.BytesIO(raw)).convert("RGBA")
        ratio = height / img.height
        new_w = max(1, int(img.width * ratio))
        img   = img.resize((new_w, height), Image.LANCZOS)
        photo = ImageTk.PhotoImage(img)
        return photo
    except Exception as e:
        print(f"[logo] falhou: {e}")
        return None


def load_icon_for_window(window):
    """Define o ícone personalizado da janela (barra de título e taskbar)."""
    import base64 as _b64, io as _io, tempfile, os, sys
    try:
        raw = _b64.b64decode(_ICON_B64)
        # Gravar .ico num ficheiro temporário — Tkinter precisa de ficheiro em disco
        tmp = tempfile.NamedTemporaryFile(suffix='.ico', delete=False)
        tmp.write(raw)
        tmp.close()
        window.iconbitmap(tmp.name)
        # Agendar limpeza após a janela carregar
        window.after(2000, lambda: os.unlink(tmp.name) if os.path.exists(tmp.name) else None)
    except Exception as e:
        print(f"[icon] falhou: {e}")


def setup_styles():
    s = ttk.Style()
    s.theme_use('clam')
    s.configure("HC.Treeview",
                background=BG_CARD,
                foreground=TEXT_PRI,
                fieldbackground=BG_CARD,
                rowheight=28,
                font=('Segoe UI', 9),
                borderwidth=0,
                relief="flat")
    s.map("HC.Treeview",
          background=[('selected', ACCENT_DRK)],
          foreground=[('selected', TEXT_PRI)])
    s.configure("HC.Treeview.Heading",
                background=BG_TOPBAR,
                foreground=TEXT_SEC,
                relief="flat",
                font=('Segoe UI', 9, 'bold'))
    s.map("HC.Treeview.Heading",
          background=[('active', BG_PANEL)])
    s.configure("HC.Vertical.TScrollbar",
                background=BG_PANEL,
                troughcolor=BG_CARD,
                bordercolor=BG_CARD,
                arrowcolor=TEXT_MUT,
                width=8)
    # Progressbar
    s.configure("HC.Horizontal.TProgressbar",
                troughcolor=BG_PANEL,
                background=ACCENT,
                borderwidth=0,
                thickness=8)
    return s

def create_button(parent, text, command, style="primary"):
    styles = {
        "primary": {"bg": ACCENT, "fg": "white", "active_bg": ACCENT_HOV, "active_fg": "white", "bold": True},
        "teal":    {"bg": BTN_TEAL_BG, "fg": BTN_TEAL_FG, "active_bg": BTN_TEAL_HOV, "active_fg": BTN_TEAL_AFG, "bold": False},
        "olive":   {"bg": BTN_OLIVE_BG, "fg": BTN_OLIVE_FG, "active_bg": BTN_OLIVE_HOV, "active_fg": BTN_OLIVE_AFG, "bold": False},
        "secondary": {"bg": BG_PANEL, "fg": TEXT_SEC, "active_bg": BG_CARD, "active_fg": TEXT_PRI, "bold": False},
        "danger":  {"bg": "#7a1a1a", "fg": DANGER, "active_bg": "#8a2020", "active_fg": "#ff6666", "bold": True},
        "warning": {"bg": "#5a4010", "fg": WARNING, "active_bg": "#6a5015", "active_fg": "#ffc060", "bold": False},
    }
    s = styles.get(style, styles["secondary"])
    font = ("Segoe UI", 9, "bold") if s["bold"] else ("Segoe UI", 9)
    return tk.Button(parent, text=text, command=command,
                     bg=s["bg"], fg=s["fg"],
                     bd=0, padx=14, pady=5,
                     font=font, cursor="hand2",
                     activebackground=s["active_bg"],
                     activeforeground=s["active_fg"],
                     relief="flat")

def create_entry(parent, show=None, **kwargs):
    entry = tk.Entry(parent, bg=BG_INPUT, fg=TEXT_PRI,
                     insertbackground=TEXT_PRI,
                     bd=0, font=("Segoe UI", 10),
                     relief="flat",
                     highlightthickness=1,
                     highlightbackground=BORDER,
                     highlightcolor=ACCENT,
                     show=show, **kwargs)
    return entry

def create_card(parent, title=None, **kwargs):
    card = tk.Frame(parent, bg=BG_CARD,
                    highlightthickness=1,
                    highlightbackground=BORDER,
                    **kwargs)
    if title:
        header = tk.Frame(card, bg=BG_TOPBAR)
        header.pack(fill=tk.X)
        tk.Label(header, text=title,
                 font=("Segoe UI", 8, "bold"),
                 bg=BG_TOPBAR, fg=TEXT_MUT,
                 padx=10, pady=6).pack(side=tk.LEFT)
        tk.Frame(card, bg=DIVIDER, height=1).pack(fill=tk.X)
    return card

class HCApplication(tk.Tk):
    def __init__(self, title="HCsoftware App", geometry="1200x700"):
        super().__init__()
        self.title(title)
        self.geometry(geometry)
        self.minsize(900, 560)
        self.configure(bg=BG_MAIN)
        self.style = setup_styles()
        self.logo_image = load_logo(36)   # logo maior na topbar
        self._build_topbar(title)
        load_icon_for_window(self)        # ícone personalizado na barra de título
        self.main_container = tk.Frame(self, bg=BG_MAIN)
        self.main_container.pack(fill=tk.BOTH, expand=True)
        self.status_bar = tk.Label(self, text="Pronto",
                                   bg=BG_TOPBAR, fg=TEXT_MUT,
                                   anchor=tk.W, padx=10, pady=3,
                                   font=("Segoe UI", 8))
        self.status_bar.pack(side=tk.BOTTOM, fill=tk.X)

    def _build_topbar(self, title):
        topbar = tk.Frame(self, bg=BG_TOPBAR, height=46)
        topbar.pack(fill=tk.X)
        topbar.pack_propagate(False)
        if self.logo_image:
            lbl = tk.Label(topbar, image=self.logo_image, bg=BG_TOPBAR)
            lbl.image = self.logo_image  # referência explícita — evita garbage collection
            lbl.pack(side=tk.LEFT, padx=(14, 8), pady=5)
            tk.Frame(topbar, bg=BORDER, width=1).pack(
                side=tk.LEFT, fill=tk.Y, pady=8, padx=8)
        tk.Label(topbar, text=title,
                 font=("Segoe UI", 12, "bold"),
                 bg=BG_TOPBAR, fg=ACCENT).pack(side=tk.LEFT, padx=4)
        tk.Frame(self, bg=ACCENT_DRK, height=2).pack(fill=tk.X)

    def set_status(self, message, status_type="info"):
        colors = {"info": TEXT_SEC, "success": SUCCESS, "error": DANGER, "warning": WARNING}
        self.status_bar.config(text=f"  {message}", fg=colors.get(status_type, TEXT_SEC))

    def create_button(self, parent, text, command, style="primary"):
        return create_button(parent, text, command, style)

    def create_entry(self, parent, **kwargs):
        return create_entry(parent, **kwargs)

    def create_card(self, parent, title=None):
        return create_card(parent, title)

def setup_log_area(parent, bg=LOG_BG, fg=LOG_RECV):
    log_frame = tk.Frame(parent, bg=bg)
    log_text = tk.Text(log_frame, bg=bg, fg=fg,
                       font=("Consolas", 9),
                       bd=0, wrap=tk.WORD,
                       state=tk.DISABLED)
    sb = ttk.Scrollbar(log_frame, style="HC.Vertical.TScrollbar", command=log_text.yview)
    sb.pack(side=tk.RIGHT, fill=tk.Y)
    log_text.configure(yscrollcommand=sb.set)
    log_text.pack(fill=tk.BOTH, expand=True, padx=4, pady=4)
    log_text.tag_config("sent", foreground=LOG_SENT)
    log_text.tag_config("recv", foreground=LOG_RECV)
    log_text.tag_config("error", foreground=DANGER)
    log_text.tag_config("warn", foreground=WARNING)
    log_text.tag_config("info", foreground=INFO)
    log_text.tag_config("ok", foreground=SUCCESS)
    log_text.tag_config("muted", foreground=TEXT_MUT)
    return log_frame, log_text
